from microcoapy import CoapServer, Coapdefines

# --- Device State ---
# These variables represent the current state of device resources.
# In a real application, these might read from actual sensors or control physical actuators.
current_temperature = 25.5  # Initial temperature value (float)
light_state = "off"         # Initial light state ("on" or "off")

# --- CoAP Resource Handlers ---

def get_temperature_handler(option_list, payload):
    """
    Handles GET requests for /sensors/temp.
    Returns the current temperature.
    """
    global current_temperature
    # Simulate temperature change for demonstration
    current_temperature += 0.1
    if current_temperature > 30.0:
        current_temperature = 20.0
    elif current_temperature < 20.0:
        current_temperature = 20.0

    # Return CoAP Content response with the temperature value
    return Coapdefines.COAP_RESPONSE_CODE.COAP_CONTENT, f"{current_temperature:.1f}C"

def get_light_handler(option_list, payload):
    """
    Handles GET requests for /actuators/light.
    Returns the current light state.
    """
    global light_state
    # Return CoAP Content response with the current light state
    return Coapdefines.COAP_RESPONSE_CODE.COAP_CONTENT, light_state

def put_light_handler(option_list, payload):
    """
    Handles PUT requests for /actuators/light.
    Updates the light state based on the payload.
    Expected payloads: "on", "off", "true", "false", "1", "0".
    """
    global light_state
    if payload is not None:
        try:
            # Decode payload from bytes to string and strip whitespace, convert to lowercase
            new_state_str = payload.decode('utf-8').strip().lower()

            if new_state_str in ["on", "true", "1"]:
                light_state = "on"
            elif new_state_str in ["off", "false", "0"]:
                light_state = "off"
            else:
                # Invalid payload received
                return Coapdefines.COAP_RESPONSE_CODE.COAP_BAD_REQUEST, \
                       "Invalid payload for light. Expected: on/off/true/false/1/0"

            print(f"Actuator: Light state updated to '{light_state}'")
            # Return CoAP Changed response
            return Coapdefines.COAP_RESPONSE_CODE.COAP_CHANGED, f"Light set to {light_state}"

        except UnicodeError:
            print("Error: Could not decode payload as UTF-8.")
            return Coapdefines.COAP_RESPONSE_CODE.COAP_BAD_REQUEST, "Payload decoding error"
        except Exception as e:
            print(f"Error processing light PUT request: {e}")
            return Coapdefines.COAP_RESPONSE_CODE.COAP_INTERNAL_SERVER_ERROR, f"Server error: {e}"
    else:
        # No payload provided for PUT request
        return Coapdefines.COAP_RESPONSE_CODE.COAP_BAD_REQUEST, "No payload for light PUT request"

# --- Main Server Logic ---

def run_coap_server():
    """
    Initializes and runs the MicroPython CoAP server.
    """
    # CoAP server will listen on this IP and port.
    # '0.0.0.0' means listen on all available network interfaces.
    # Standard CoAP port is 5683.
    coap_server_ip = '0.0.0.0'
    coap_server_port = 5683

    print(f"Starting CoAP server on {coap_server_ip}:{coap_server_port}...")
    server = None # Initialize server variable to None

    try:
        # Create a CoapServer instance
        server = CoapServer(coap_server_ip, coap_server_port)

        # Register resources and their respective handlers
        server.add_resource('sensors/temp', callback_get=get_temperature_handler)
        server.add_resource('actuators/light', callback_get=get_light_handler, callback_put=put_light_handler)

        print("CoAP resources registered:")
        print("  GET /sensors/temp     (Returns current temperature)")
        print("  GET /actuators/light  (Returns current light state)")
        print("  PUT /actuators/light  (Updates light state with payload: 'on', 'off', '1', '0', etc.)")

        # Start the server loop to continuously listen for CoAP requests
        # In a single-threaded MicroPython environment, this loop will block.
        # Ensure other critical tasks are either handled asynchronously or in separate threads
        # if your MicroPython port supports threading (_thread module).
        while True:
            server.loop() # Process any pending CoAP packets
            time.sleep(0.05) # Small delay to yield CPU, adjust as needed for responsiveness vs power-saving

    except OSError as e:
        if e.args[0] == 98: # EADDRINUSE error code
            print(f"Error: Port {coap_server_port} already in use. Is another instance running?")
        else:
            print(f"Network or Socket Error: {e}")
    except KeyboardInterrupt:
        print("\nCoAP Server stopped by user (KeyboardInterrupt).")
    except Exception as e:
        print(f"An unexpected error occurred: {e}")
    finally:
        if server:
            print("Closing CoAP server socket...")
            server.close() # Ensure the server socket is properly closed
        print("CoAP Server shut down.")

